import{_ as t,o as l,c as i,ag as a}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Editor Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Shell-Aliase fuer Neovim, VS Code, Vim, Nano, Emacs und Sublime Text. Dateien schneller bearbeiten mit universellen Verknuepfungen.","frontmatter":{"title":"Editor Aliase | Dotfiles","description":"Shell-Aliase fuer Neovim, VS Code, Vim, Nano, Emacs und Sublime Text. Dateien schneller bearbeiten mit universellen Verknuepfungen.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Editor Aliase preview","canonical":"/de/aliases/editor/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Editor Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Editor Aliase - Dotfiles (DE)","permalink":"/de/aliases/editor/","sidebar":true,"meta":[{"name":"keywords","content":"editor aliase, neovim, vim, vscode, nano, emacs, sublime text, shell verknuepfungen, dotfiles"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Shell-Aliase fuer Neovim, VS Code, Vim, Nano, Emacs und Sublime Text."},{"name":"twitter:title","content":"Editor Aliase - Dotfiles"},{"name":"og:title","content":"Editor Aliase - Dotfiles"},{"name":"og:description","content":"Shell-Aliase fuer Neovim, VS Code, Vim, Nano, Emacs und Sublime Text."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/editor/index.md","filePath":"de/aliases/editor/index.md","lastUpdated":1773010926000}'),d={name:"de/aliases/editor/index.md"};function n(r,e,s,o,c,f){return l(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="editor-aliase" tabindex="-1">Editor Aliase <a class="header-anchor" href="#editor-aliase" aria-label="Permalink to &quot;Editor Aliase&quot;">​</a></h1><p>Verknuepfungen zum Starten und Konfigurieren Ihres bevorzugten Texteditors.</p><h2 id="uebersicht" tabindex="-1">Uebersicht <a class="header-anchor" href="#uebersicht" aria-label="Permalink to &quot;Uebersicht&quot;">​</a></h2><p>Editor-Aliase bieten eine einheitliche Schnittstelle fuer Textbearbeitung ueber mehrere Anwendungen. In <code>editor.aliases.sh</code> definiert und automatisch von Chezmoi geladen, arbeiten diese Verknuepfungen zusammen mit <code>editor.sh</code>, um den besten verfuegbaren Editor auf Ihrem System zu erkennen und zu konfigurieren.</p><p>Das System unterstuetzt Neovim, Visual Studio Code, Vim, Nano, Emacs, Sublime Text und Atom. Universelle Aliase passen sich an den aktiven Editor an, waehrend spezialisierte Aliase editor-spezifische Funktionen bieten.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="universelle-aliase" tabindex="-1">Universelle Aliase <a class="header-anchor" href="#universelle-aliase" aria-label="Permalink to &quot;Universelle Aliase&quot;">​</a></h3><p>Diese Aliase funktionieren mit jedem von <code>editor.sh</code> konfigurierten Editor.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>e</code></td><td style="text-align:left;">Schneller Bearbeitungsbefehl</td></tr><tr><td style="text-align:left;"><code>edit</code></td><td style="text-align:left;">Standard-Bearbeitungsbefehl</td></tr><tr><td style="text-align:left;"><code>editor</code></td><td style="text-align:left;">Vollstaendiger Editor-Befehl</td></tr><tr><td style="text-align:left;"><code>mate</code></td><td style="text-align:left;">TextMate-aehnlicher Befehl</td></tr><tr><td style="text-align:left;"><code>n</code></td><td style="text-align:left;">Kurzer Bearbeitungs-Alias</td></tr><tr><td style="text-align:left;"><code>v</code></td><td style="text-align:left;">Vim-aehnlicher Bearbeitungs-Alias</td></tr></tbody></table><h3 id="neovim-aliase" tabindex="-1">Neovim Aliase <a class="header-anchor" href="#neovim-aliase" aria-label="Permalink to &quot;Neovim Aliase&quot;">​</a></h3><p>Verfuegbar wenn Neovim der primaere Editor ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>vi</code></td><td style="text-align:left;">Weiterleitung zu Neovim</td></tr><tr><td style="text-align:left;"><code>vim</code></td><td style="text-align:left;">Weiterleitung zu Neovim</td></tr><tr><td style="text-align:left;"><code>nvimrc</code></td><td style="text-align:left;">Neovim Vimscript-Konfiguration bearbeiten</td></tr><tr><td style="text-align:left;"><code>nvimlua</code></td><td style="text-align:left;">Neovim Lua-Konfiguration bearbeiten</td></tr><tr><td style="text-align:left;"><code>nvimconf</code></td><td style="text-align:left;">Neovim-Konfigurationsverzeichnis oeffnen</td></tr></tbody></table><h3 id="visual-studio-code-aliase" tabindex="-1">Visual Studio Code Aliase <a class="header-anchor" href="#visual-studio-code-aliase" aria-label="Permalink to &quot;Visual Studio Code Aliase&quot;">​</a></h3><p>Verfuegbar wenn VS Code installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>vsc</code></td><td style="text-align:left;">VS Code starten</td></tr><tr><td style="text-align:left;"><code>vsca</code></td><td style="text-align:left;">Ordner zum aktuellen Fenster hinzufuegen</td></tr><tr><td style="text-align:left;"><code>vscd</code></td><td style="text-align:left;">Zwei Dateien vergleichen</td></tr><tr><td style="text-align:left;"><code>vscn</code></td><td style="text-align:left;">Neues Fenster oeffnen</td></tr><tr><td style="text-align:left;"><code>vscr</code></td><td style="text-align:left;">Fenster beim Oeffnen von Dateien wiederverwenden</td></tr><tr><td style="text-align:left;"><code>vscu</code></td><td style="text-align:left;">Mit benutzerdefiniertem Datenverzeichnis oeffnen</td></tr><tr><td style="text-align:left;"><code>vsced</code></td><td style="text-align:left;">Mit benutzerdefiniertem Erweiterungsverzeichnis oeffnen</td></tr><tr><td style="text-align:left;"><code>vscex</code></td><td style="text-align:left;">VS Code-Erweiterung installieren</td></tr><tr><td style="text-align:left;"><code>vsclist</code></td><td style="text-align:left;">Installierte Erweiterungen auflisten</td></tr></tbody></table><h3 id="vim-aliase" tabindex="-1">Vim Aliase <a class="header-anchor" href="#vim-aliase" aria-label="Permalink to &quot;Vim Aliase&quot;">​</a></h3><p>Verfuegbar wenn Vim der primaere Editor ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>vi</code></td><td style="text-align:left;">Weiterleitung zu Vim</td></tr><tr><td style="text-align:left;"><code>vimrc</code></td><td style="text-align:left;">Vim-Konfigurationsdatei bearbeiten</td></tr><tr><td style="text-align:left;"><code>vimconf</code></td><td style="text-align:left;">Vim-Konfigurationsverzeichnis oeffnen</td></tr></tbody></table><h3 id="nano-aliase" tabindex="-1">Nano Aliase <a class="header-anchor" href="#nano-aliase" aria-label="Permalink to &quot;Nano Aliase&quot;">​</a></h3><p>Verfuegbar wenn Nano der primaere Editor ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>nanorc</code></td><td style="text-align:left;">Nano-Konfigurationsdatei bearbeiten</td></tr><tr><td style="text-align:left;"><code>ne</code></td><td style="text-align:left;">Erweitertes Nano mit Zeilennummern und sanftem Scrollen</td></tr></tbody></table><h3 id="emacs-aliase" tabindex="-1">Emacs Aliase <a class="header-anchor" href="#emacs-aliase" aria-label="Permalink to &quot;Emacs Aliase&quot;">​</a></h3><p>Verfuegbar wenn Emacs installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>em</code></td><td style="text-align:left;">Emacs starten</td></tr><tr><td style="text-align:left;"><code>emacs-nw</code></td><td style="text-align:left;">Emacs im Terminal-Modus ausfuehren</td></tr><tr><td style="text-align:left;"><code>emacsc</code></td><td style="text-align:left;">Emacs-Client starten</td></tr><tr><td style="text-align:left;"><code>emacsrc</code></td><td style="text-align:left;">Emacs-Konfigurationsdatei bearbeiten</td></tr><tr><td style="text-align:left;"><code>et</code></td><td style="text-align:left;">Schnelles Terminal-basiertes Emacs</td></tr></tbody></table><h3 id="sublime-text-aliase" tabindex="-1">Sublime Text Aliase <a class="header-anchor" href="#sublime-text-aliase" aria-label="Permalink to &quot;Sublime Text Aliase&quot;">​</a></h3><p>Verfuegbar wenn Sublime Text installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>st</code></td><td style="text-align:left;">Sublime Text starten</td></tr><tr><td style="text-align:left;"><code>stt</code></td><td style="text-align:left;">Aktuelles Verzeichnis in Sublime Text oeffnen</td></tr><tr><td style="text-align:left;"><code>stn</code></td><td style="text-align:left;">In neuem Sublime Text-Fenster oeffnen</td></tr></tbody></table><h3 id="atom-aliase" tabindex="-1">Atom Aliase <a class="header-anchor" href="#atom-aliase" aria-label="Permalink to &quot;Atom Aliase&quot;">​</a></h3><p>Verfuegbar wenn Atom installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>a</code></td><td style="text-align:left;">Atom starten</td></tr><tr><td style="text-align:left;"><code>at</code></td><td style="text-align:left;">Aktuelles Verzeichnis in Atom oeffnen</td></tr><tr><td style="text-align:left;"><code>an</code></td><td style="text-align:left;">In neuem Atom-Fenster oeffnen</td></tr></tbody></table><h3 id="konfigurationsbearbeitung" tabindex="-1">Konfigurationsbearbeitung <a class="header-anchor" href="#konfigurationsbearbeitung" aria-label="Permalink to &quot;Konfigurationsbearbeitung&quot;">​</a></h3><p>Die <code>editrc</code>-Funktion bietet schnellen Zugriff auf gaengige Konfigurationsdateien.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Befehl</th><th style="text-align:left;">Zieldatei</th></tr></thead><tbody><tr><td style="text-align:left;"><code>editrc bash</code></td><td style="text-align:left;"><code>~/.bashrc</code></td></tr><tr><td style="text-align:left;"><code>editrc zsh</code></td><td style="text-align:left;"><code>~/.zshrc</code></td></tr><tr><td style="text-align:left;"><code>editrc vim</code></td><td style="text-align:left;"><code>~/.vimrc</code></td></tr><tr><td style="text-align:left;"><code>editrc nvim</code></td><td style="text-align:left;">Neovim init-Datei</td></tr><tr><td style="text-align:left;"><code>editrc tmux</code></td><td style="text-align:left;"><code>~/.tmux.conf</code></td></tr><tr><td style="text-align:left;"><code>editrc git</code></td><td style="text-align:left;"><code>~/.gitconfig</code></td></tr><tr><td style="text-align:left;"><code>editrc ssh</code></td><td style="text-align:left;"><code>~/.ssh/config</code></td></tr><tr><td style="text-align:left;"><code>editrc alias</code></td><td style="text-align:left;"><code>~/.dotfiles/aliases</code></td></tr><tr><td style="text-align:left;"><code>editrc dotfiles</code></td><td style="text-align:left;"><code>~/.dotfiles</code></td></tr></tbody></table>',33)])])}const h=t(d,[["render",n]]);export{u as __pageData,h as default};
